graphql.query:
mutation AuthenticateUser($input: LoginInputTypeInput!) {
  login(input: $input) {
    success
    token
    expiresAt
  }
}

query AggregateData($input: AggregateDataInputTypeInput!) {
  aggregateData(input: $input) {
    items {
      source
      title
      description
      category
      publishedAt
      relevanceScore
      url
    }
    providers {
      source
      success
      usedFallback
      responseTimeMs
      errorMessage
    }
  }
}

